mapper.select:
SELECT st.settlement_id, st.settlement_no, st.provider_id, p.provider_name AS providerName, st.staff_id, s.staff_name AS staffName, st.order_id, o.order_no AS orderNo, st.elder_id, e.elder_name AS elderName, st.service_date, st.total_amount, st.subsidy_amount, st.self_pay_amount, st.payment_status, st.payment_time, st.create_time FROM t_settlement st LEFT JOIN t_provider p ON st.provider_id = p.provider_id LEFT JOIN t_staff s ON st.staff_id = s.staff_id LEFT JOIN t_order o ON st.order_id = o.order_id LEFT JOIN t_elder e ON st.elder_id = e.elder_id WHERE 1=1
AND st.settlement_no LIKE CONCAT('%', #{query.settlementNo}, '%')
AND st.provider_id = #{query.providerId}
AND p.provider_name LIKE CONCAT('%', #{query.providerName}, '%')
AND st.staff_id = #{query.staffId}
AND st.settlement_no LIKE CONCAT('%', #{query.orderNo}, '%')
AND EXISTS ( SELECT 1 FROM t_order o WHERE o.provider_id = st.provider_id AND o.elder_name LIKE CONCAT('%', #{query.elderName}, '%') )
AND st.payment_status = #{query.status}
AND st.create_time >= #{query.startDate}
AND st.create_time <= #{query.endDate}
ORDER BY st.create_time DESC
